// HOF that RETURNS a function (function factory)
function multiplier(factor) {
  return (number) => number * factor; // captures 'factor' via closure
}

const double   = multiplier(2);
const triple   = multiplier(3);
const tenTimes = multiplier(10);

console.log(double(5));   // 10
console.log(triple(5));   // 15
console.log(tenTimes(5)); // 50

// HOF that ACCEPTS a function (built-in example)
const scores = [45, 78, 90, 62, 88];
const passing = scores.filter(score => score >= 70);
const doubled = scores.map(score => score * 2);
const total   = scores.reduce((acc, s) => acc + s, 0);

console.log(passing); // [78, 90, 88]
console.log(total);   // 363

6_edge_case.code:
function makeAdder(x) {
  return function add(y) { return x + y; };
  // Each call to makeAdder creates a NEW 'add' function object
  // that closes over a DIFFERENT 'x'
}

const add5  = makeAdder(5);
const add10 = makeAdder(10);

console.log(add5(3));  // 8  — closes over x=5
console.log(add10(3)); // 13 — closes over x=10
console.log(add5 === add10); // false — they are distinct function objects
